import requests

# Define RabbitMQ credentials and base URL
RABBITMQ_USER = 'your_username'
RABBITMQ_PASSWORD = 'your_password'
RABBITMQ_URL = 'http://localhost:15672/api'

def create_virtual_host(vhost_name):
    url = f"{RABBITMQ_URL}/vhosts/{vhost_name}"
    response = requests.put(url, auth=(RABBITMQ_USER, RABBITMQ_PASSWORD))
    if response.status_code == 204:
        print(f"Virtual host '{vhost_name}' created successfully.")
    else:
        print(f"Failed to create virtual host '{vhost_name}'. Status code: {response.status_code}")

def set_permissions(vhost_name, user, configure='.*', write='.*', read='.*'):
    url = f"{RABBITMQ_URL}/permissions/{vhost_name}/{user}"
    payload = {
        "configure": configure,
        "write": write,
        "read": read
    }
    response = requests.put(url, json=payload, auth=(RABBITMQ_USER, RABBITMQ_PASSWORD))
    if response.status_code == 204:
        print(f"Permissions set successfully for user '{user}' on vhost '{vhost_name}'.")
    else:
        print(f"Failed to set permissions for user '{user}' on vhost '{vhost_name}'. Status code: {response.status_code}")

def main():
    # Example virtual hosts and users
    vhosts = ['app1_vhost', 'app2_vhost']
    users = {
        'app1_user': {'permissions': ('.*', '.*', '.*')},
        'app2_user': {'permissions': ('.*', '.*', '.*')}
    }

    for vhost in vhosts:
        create_virtual_host(vhost)
    
    for user, details in users.items():
        set_permissions(details['vhost'], user, *details['permissions'])

if __name__ == "__main__":
    main()